#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <string.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* getNode(Node** arr, int* cnt, int value) {
    for (int i = 0; i < *cnt; ++i) {
        if (arr[i]->val == value) return arr[i];
    }
    Node* nd = (Node*)malloc(sizeof(Node));
    nd->val = value;
    nd->left = nd->right = NULL;
    arr[(*cnt)++] = nd;
    return nd;
}

int isBST(Node* node, long long minVal, long long maxVal) {
    if (!node) return 1;
    if (node->val <= minVal || node->val >= maxVal) return 0;
    return isBST(node->left, minVal, node->val) && isBST(node->right, node->val, maxVal);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node* nodes[200]; // N ≤ 15, safe size
        int nodeCnt = 0;
        int childMark[200000] = {0}; // map value to child flag (value ≤ 100000)
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir;
            scanf("%d %d %c", &p, &c, &dir);
            Node* parent = getNode(nodes, &nodeCnt, p);
            Node* child  = getNode(nodes, &nodeCnt, c);
            if (dir == 'L') parent->left = child; else parent->right = child;
            childMark[c] = 1;
        }
        // find root (node that never appeared as child)
        Node* root = NULL;
        for (int i = 0; i < nodeCnt; ++i) {
            if (!childMark[nodes[i]->val]) { root = nodes[i]; break; }
        }
        if (isBST(root, LLONG_MIN, LLONG_MAX)) printf("YES\n");
        else printf("NO\n");
        // free memory (optional for contest)
        for (int i = 0; i < nodeCnt; ++i) free(nodes[i]);
    }
    return 0;
}

