#include <bits/stdc++.h>
using namespace std;

struct Node {
    int val;
    Node* left = nullptr;
    Node* right = nullptr;
    Node(int v) : val(v) {}
};

bool isBST(Node* node, long long minVal, long long maxVal) {
    if (!node) return true;
    if (node->val <= minVal || node->val >= maxVal) return false;
    return isBST(node->left, minVal, node->val) && isBST(node->right, node->val, maxVal);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin>>N;
        unordered_map<int, Node*> mp;
        unordered_set<int> childSet;
        for (int i=0;i<N-1;++i) {
            int p,c; char dir; cin>>p>>c>>dir;
            if (!mp.count(p)) mp[p]=new Node(p);
            if (!mp.count(c)) mp[c]=new Node(c);
            if (dir=='L') mp[p]->left = mp[c]; else mp[p]->right = mp[c];
            childSet.insert(c);
        }
        Node* root = nullptr;
        for (auto &kv: mp) {
            if (!childSet.count(kv.first)) { root = kv.second; break; }
        }
        cout << (isBST(root, LLONG_MIN, LLONG_MAX) ? "YES" : "NO") << '\n';
        // clean up
        for (auto &kv: mp) delete kv.second;
    }
    return 0;
}

