import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static boolean isBST(Node node, long min, long max) {
        if (node == null) return true;
        if (node.val <= min || node.val >= max) return false;
        return isBST(node.left, min, node.val) && isBST(node.right, node.val, max);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                map.putIfAbsent(p, new Node(p));
                map.putIfAbsent(c, new Node(c));
                Node parent = map.get(p);
                Node child = map.get(c);
                if (dir == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            for (Map.Entry<Integer, Node> e : map.entrySet()) {
                if (!childSet.contains(e.getKey())) { root = e.getValue(); break; }
            }
            out.append(isBST(root, Long.MIN_VALUE, Long.MAX_VALUE) ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

