import sys

def is_bst(node, lo, hi):
    if node is None:
        return True
    if not (lo < node[0] < hi):
        return False
    return is_bst(node[1], lo, node[0]) and is_bst(node[2], node[0], hi)

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nodes = {}
        children = set()
        for _ in range(N-1):
            p, c, d = next(it).split()
            p = int(p); c = int(c)
            if p not in nodes:
                nodes[p] = [p, None, None]
            if c not in nodes:
                nodes[c] = [c, None, None]
            if d == 'L':
                nodes[p][1] = nodes[c]
            else:
                nodes[p][2] = nodes[c]
            children.add(c)
        root = None
        for val in nodes:
            if val not in children:
                root = nodes[val]
                break
        out_lines.append('YES' if is_bst(root, -float('inf'), float('inf')) else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

